function slug(s: string) { return s.toLowerCase().trim().replace(/[^a-z0-9]+/g, '-'); }

export const suggest = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const q = String(req.query.q ?? '');
    const tags = await TagModel.find({ slug: { $regex: `^${slug(q)}` } }).sort({ usageCount: -1 }).limit(10).lean();
    res.json({ tags });
  } catch (err) { next(err); }
};

export const bulkApply = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { articleIds, addTagIds, removeTagIds } = req.body as { articleIds: string[]; addTagIds: string[]; removeTagIds: string[] };
    if (addTagIds?.length) await ArticleModel.updateMany({ _id: { $in: articleIds } }, { $addToSet: { tagIds: { $each: addTagIds } } });
    if (removeTagIds?.length) await ArticleModel.updateMany({ _id: { $in: articleIds } }, { $pullAll: { tagIds: removeTagIds } });
    res.json({ ok: true });
  } catch (err) { next(err); }
};

