import { Request, Response, NextFunction } from 'express';
import { fileTypeFromBuffer } from 'file-type';
import { HttpError } from '../errors/http-error';

const ALLOWED = new Set(['image/jpeg','image/png','image/webp','application/pdf']);

export async function fileTypeCheck(req: Request, _res: Response, next: NextFunction) {
  try {
    if (!req.file) return next();
    const sniffed = await fileTypeFromBuffer(req.file.buffer);
    if (!sniffed || !ALLOWED.has(sniffed.mime)) throw new HttpError(415, 'UNSUPPORTED_TYPE');
    if (req.file.mimetype !== sniffed.mime) throw new HttpError(400, 'TYPE_MISMATCH');
    req.file.mimetype = sniffed.mime;
    next();
  } catch (err) { next(err); }
}

