import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { io } from 'socket.io-client';

const SIZE = 50;

function tempToColor(t: number, min: number, max: number, c: THREE.Color): THREE.Color {
  const n = (t - min) / Math.max(0.001, max - min);
  return c.setHSL((1 - n) * 0.66, 0.8, 0.5);
}

function Surface({ token }: { token: string }) {
  const meshRef = useRef<THREE.Mesh>(null);
  const gridRef = useRef<number[][]>(Array.from({ length: SIZE }, () => Array(SIZE).fill(20)));

  useEffect(() => {
    const socket = io('/heatmap', { auth: { token } });
    socket.on('grid', (g: number[][]) => { gridRef.current = g; });
    return () => { socket.disconnect(); };
  }, [token]);

  useFrame(() => {
    const mesh = meshRef.current; if (!mesh) return;
    const geom = mesh.geometry as THREE.PlaneGeometry;
    const pos = geom.attributes.position;
    const colorsAttr = geom.attributes.color as THREE.BufferAttribute;
    const c = new THREE.Color();
    let min = Infinity, max = -Infinity;
    for (const row of gridRef.current) for (const v of row) { if (v < min) min = v; if (v > max) max = v; }
    for (let y = 0; y <= SIZE; y++) for (let x = 0; x <= SIZE; x++) {
      const i = y * (SIZE + 1) + x;
      const v = gridRef.current[Math.min(SIZE - 1, y)][Math.min(SIZE - 1, x)];
      pos.setY(i, v * 0.2);
      tempToColor(v, min, max, c);
      colorsAttr.setXYZ(i, c.r, c.g, c.b);
    }
    pos.needsUpdate = true;
    colorsAttr.needsUpdate = true;
    geom.computeVertexNormals();
  });

  return (
    <mesh ref={meshRef} rotation={[-Math.PI / 2, 0, 0]}>
      <planeGeometry args={[20, 20, SIZE, SIZE]} onUpdate={(g) => { g.setAttribute('color', new THREE.BufferAttribute(new Float32Array(((SIZE + 1) ** 2) * 3), 3)); }} />
      <meshStandardMaterial vertexColors flatShading={false} />
    </mesh>
  );
}

