const TIER_LIMITS: Record<string, number> = { free: 60, pro: 600, enterprise: 6000 };
const WINDOW_MS = 60_000;

export async function publicApiLimits(req: Request, res: Response, next: NextFunction) {
  try {
    const tenantSlug = req.params.tenant;
    const org = await OrgModel.findOne({ slug: tenantSlug }).lean();
    if (!org) throw new HttpError(404, 'TENANT_NOT_FOUND');
    const limit = TIER_LIMITS[org.tier ?? 'free'];
    const key = `pub:${org._id}:${req.ip}`;
    const now = Date.now();
    const count = await redis.eval(`local k=KEYS[1] local now=tonumber(ARGV[1]) local w=tonumber(ARGV[2]) redis.call('ZREMRANGEBYSCORE',k,0,now-w) redis.call('ZADD',k,now,tostring(now)) redis.call('PEXPIRE',k,w) return redis.call('ZCARD',k)`, { keys: [key], arguments: [String(now), String(WINDOW_MS)] });
    res.setHeader('X-RateLimit-Limit', String(limit));
    res.setHeader('X-RateLimit-Remaining', String(Math.max(0, limit - Number(count))));
    if (Number(count) > limit) throw new HttpError(429, 'RATE_LIMIT');
    (req as { orgId?: string }).orgId = String(org._id);
    next();
  } catch (err) { next(err); }
}

