import { ProductModel } from '../models/product.model';

export async function importProducts(items: { sku: string; name: string }[]) {
  const CHUNK = 500;
  let upserted = 0;
  const errors: { sku: string; reason: string }[] = [];
  for (let i = 0; i < items.length; i += CHUNK) {
    const slice = items.slice(i, i + CHUNK);
    const ops = slice.map(it => ({ updateOne: { filter: { sku: it.sku }, update: { $set: it }, upsert: true } }));
    try {
      const r = await ProductModel.bulkWrite(ops, { ordered: false });
      upserted += (r.upsertedCount ?? 0) + (r.modifiedCount ?? 0);
    } catch (e: unknown) {
      const writeErrors = (e as { writeErrors?: { index: number; errmsg: string }[] }).writeErrors ?? [];
      for (const w of writeErrors) errors.push({ sku: slice[w.index]?.sku ?? 'unknown', reason: w.errmsg });
    }
  }
  return { upserted, errors };
}

import { useEffect, useRef } from 'react';
import { io } from 'socket.io-client';

export function useMyPresence(token: string) {
  const socketRef = useRef<ReturnType<typeof io> | null>(null);
  const lastActivity = useRef(Date.now());
  useEffect(() => {
    const socket = io('/presence', { auth: { token } });
    socketRef.current = socket;
    const markActive = () => { lastActivity.current = Date.now(); };
    window.addEventListener('mousemove', markActive);
    window.addEventListener('keydown', markActive);
    window.addEventListener('focus', markActive);
    const beat = setInterval(() => {
      const idle = Date.now() - lastActivity.current > 5 * 60_000;
      const visible = document.visibilityState === 'visible';
      const status = !visible ? 'offline' : idle ? 'idle' : 'online';
      socket.emit('heartbeat', { status });
    }, 30_000);
    return () => { clearInterval(beat); window.removeEventListener('mousemove', markActive); window.removeEventListener('keydown', markActive); window.removeEventListener('focus', markActive); socket.disconnect(); };
  }, [token]);
}

import { Server, Socket } from 'socket.io';
import { redis } from '../infra/redis';

export function attachPresenceNamespace(io: Server) {
  const ns = io.of('/presence');
  ns.on('connection', (socket: Socket) => {
    const userId = (socket as any).data.userId as string;
    socket.on('heartbeat', async ({ status }: { status: string }) => {
      const prev = await redis.hGet('presence', userId);
      const previousStatus = prev ? JSON.parse(prev).status : null;
      await redis.hSet('presence', userId, JSON.stringify({ status, lastSeen: Date.now() }));
      if (previousStatus !== status) ns.emit('peer:status', { userId, status });
    });
    socket.on('disconnect', async () => {
      await redis.hSet('presence', userId, JSON.stringify({ status: 'offline', lastSeen: Date.now() }));
      ns.emit('peer:status', { userId, status: 'offline' });
    });
  });
}

