import { Request, Response, NextFunction } from 'express';
import ipaddr from 'ipaddr.js';
import { AllowedIpModel } from '../models/allowed-ip.model';
import { HttpError } from '../errors/http-error';
import { auditLog } from '../services/audit.service';

function matchCidr(ip: string, cidr: string): boolean {
  const [base, prefix] = cidr.split('/');
  try {
    const addr = ipaddr.parse(ip);
    const baseAddr = ipaddr.parse(base);
    if (addr.kind() !== baseAddr.kind()) return false;
    return addr.match(baseAddr, Number(prefix));
  } catch { return false; }
}

export async function ipAllowlist(req: Request, _res: Response, next: NextFunction) {
  try {
    if (!req.user) return next();
    const allowed = await AllowedIpModel.find({ userId: req.user.id }).lean();
    if (allowed.length === 0) return next();
    const ip = req.ip ?? '0.0.0.0';
    if (allowed.some(a => matchCidr(ip, a.cidr))) return next();
    if (req.headers['x-2fa-bypass-token']) return next();
    await auditLog({ actorId: req.user.id, action: 'ip.blocked', target: ip });
    throw new HttpError(403, 'IP_NOT_ALLOWED');
  } catch (err) { next(err); }
}

import { Canvas, ThreeEvent } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { useLayoutEffect, useMemo, useRef, useState } from 'react';
import * as THREE from 'three';

export function Zones3D({ zones }: { zones: { id: string; name: string; count: number }[] }) {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const [hover, setHover] = useState<{ zone: typeof zones[number]; x: number; y: number } | null>(null);

  useLayoutEffect(() => {
    const mesh = meshRef.current; if (!mesh) return;
    const m = new THREE.Matrix4();
    const c = new THREE.Color();
    let inst = 0;
    zones.forEach((z, zi) => {
      const colorHue = (zi * 47) % 360;
      for (let stack = 0; stack < z.count; stack++) {
        m.setPosition(zi * 2, stack * 0.5 + 0.25, 0);
        mesh.setMatrixAt(inst, m);
        c.setHSL(colorHue / 360, 0.6, 0.5);
        mesh.setColorAt(inst, c);
        inst++;
      }
    });
    mesh.count = inst;
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
  }, [zones]);

  const onMove = (e: ThreeEvent<PointerEvent>) => {
    if (e.instanceId === undefined) { setHover(null); return; }
    let acc = 0;
    for (const z of zones) {
      acc += z.count;
      if (e.instanceId < acc) { setHover({ zone: z, x: e.clientX, y: e.clientY }); return; }
    }
  };

  return (
    <div className="w-full h-screen relative">
      <Canvas camera={{ position: [10, 8, 12] }}>
        <ambientLight intensity={0.6} />
        <directionalLight position={[10, 20, 10]} intensity={0.7} />
        <instancedMesh ref={meshRef} args={[undefined, undefined, 5000]} onPointerMove={onMove} onPointerOut={() => setHover(null)}>
          <boxGeometry args={[1, 0.4, 1]} />
          <meshStandardMaterial />
        </instancedMesh>
        <OrbitControls />
      </Canvas>
      {hover && <div className="absolute bg-black text-white px-2 py-1 text-xs rounded pointer-events-none" style={{ left: hover.x + 8, top: hover.y + 8 }}>{hover.zone.name}: {hover.zone.count}</div>}
    </div>
  );
}

