import { useEffect, useState, useRef } from 'react';
import type { Socket } from 'socket.io-client';

export function CollabFormField({ formId, field, socket, currentUserId }: { formId: string; field: string; socket: Socket; currentUserId: string }) {
  const [value, setValue] = useState('');
  const [lastOther, setLastOther] = useState<number>(0);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const handler = (msg: { formId: string; field: string; value: string; userId: string }) => {
      if (msg.formId !== formId || msg.field !== field) return;
      if (msg.userId !== currentUserId) {
        setValue(msg.value);
        setLastOther(Date.now());
      }
    };
    socket.on('form:field', handler);
    return () => { socket.off('form:field', handler); };
  }, [formId, field, socket, currentUserId]);

  const onChange = (next: string) => {
    setValue(next);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => socket.emit('form:field', { formId, field, value: next }), 300);
  };

  const highlight = Date.now() - lastOther < 2000;
  return (
    <input value={value} onChange={e => onChange(e.target.value)} className={`border rounded p-2 ${highlight ? 'border-amber-500' : ''}`} />
  );
}

import { Server, Socket } from 'socket.io';
export function attachFormNamespace(io: Server) {
  const ns = io.of('/form');
