export async function loadSecrets() {
  if (process.env.NODE_ENV === 'development') return;
  const client = new SecretsManagerClient({});
  const secretIds = (process.env.SECRET_IDS ?? '').split(',').filter(Boolean);
  for (const id of secretIds) {
    const out = await client.send(new GetSecretValueCommand({ SecretId: id }));
    const json = JSON.parse(out.SecretString ?? '{}');
    for (const [k, v] of Object.entries(json)) process.env[k] = String(v);
  }
}

