import { execSync } from 'node:child_process';
import fs from 'node:fs';

const TYPES: Record<string, string> = { feat: 'Features', fix: 'Bug Fixes', perf: 'Performance', refactor: 'Refactors' };
const from = process.argv[2];
const to = process.argv[3] ?? 'HEAD';
const log = execSync(`git log ${from}..${to} --pretty=format:%H||%s||%b||(end)`, { encoding: 'utf8' }).split('(end)').filter(Boolean);

const groups: Record<string, string[]> = {};
for (const entry of log) {
  const [, subject] = entry.trim().split('||');
  const match = /^(\w+)(?:\(.*\))?:\s+(.+?)(?:\s+\(#(\d+)\))?$/.exec(subject);
  if (!match) continue;
  const [, type, message, pr] = match;
  const title = TYPES[type]; if (!title) continue;
  groups[title] = groups[title] ?? [];
  groups[title].push(pr ? `- ${message} (#${pr})` : `- ${message}`);
}

let out = `## ${to}\n\n`;
for (const [title, lines] of Object.entries(groups)) {
  out += `### ${title}\n${lines.join('\n')}\n\n`;
}
fs.appendFileSync('CHANGELOG.md', out);
console.log('Changelog appended');

