function Assembly({ url, explodeProgress }: { url: string; explodeProgress: { value: number } }) {
  const { scene } = useGLTF(url);
  const initial = useRef<Map<THREE.Mesh, { origin: THREE.Vector3; outward: THREE.Vector3 }> | null>(null);

  useEffect(() => {
    const center = new THREE.Box3().setFromObject(scene).getCenter(new THREE.Vector3());
    const map = new Map<THREE.Mesh, { origin: THREE.Vector3; outward: THREE.Vector3 }>();
    scene.traverse(obj => {
      const m = obj as THREE.Mesh;
      if (!m.isMesh) return;
      const origin = m.position.clone();
      const partCenter = new THREE.Box3().setFromObject(m).getCenter(new THREE.Vector3());
      const outward = partCenter.clone().sub(center).normalize().multiplyScalar(2);
      map.set(m, { origin, outward });
    });
    initial.current = map;
  }, [scene]);

  useFrame(() => {
    if (!initial.current) return;
    for (const [mesh, { origin, outward }] of initial.current) {
      mesh.position.copy(origin).addScaledVector(outward, explodeProgress.value);
    }
  });
  return <primitive object={scene} />;
}

export function AssemblyView({ url }: { url: string }) {
  const [exploded, setExploded] = useState(false);
  const progress = useRef({ value: 0 });
  return (
    <div className="w-full h-screen relative">
      <button onClick={() => setExploded(e => !e)} className="absolute top-2 left-2 z-10 px-3 py-1 bg-white rounded">{exploded ? 'Collapse' : 'Explode'}</button>
      <Canvas>
        <ambientLight intensity={0.6} />
        <directionalLight position={[10, 10, 10]} intensity={0.8} />
        <Progress target={exploded ? 1 : 0} progress={progress} />
        <Assembly url={url} explodeProgress={progress.current} />
        <OrbitControls />
      </Canvas>
    </div>
  );
}

function Progress({ target, progress }: { target: number; progress: { current: { value: number } } }) {
  useFrame(() => { progress.current.value += (target - progress.current.value) * 0.1; });
  return null;
}

