import { Server, Socket } from 'socket.io';

type Stroke = { id: string; bbox: [number, number, number, number]; points: { x: number; y: number }[]; color: string };
const boards = new Map<string, { strokes: Stroke[] }>();

export function attachWhiteboardNamespace(io: Server) {
  const ns = io.of('/whiteboard');
  ns.on('connection', (socket: Socket) => {
    let board: string | null = null;
    let viewport: [number, number, number, number] = [0, 0, 1000, 1000];
    socket.on('board:join', (boardId: string) => { board = boardId; socket.join(`board:${boardId}`); });
    socket.on('viewport:set', (v: [number, number, number, number]) => {
      viewport = v;
      if (!board) return;
      const b = boards.get(board); if (!b) return;
      const visible = b.strokes.filter(s => intersects(s.bbox, viewport));
      socket.emit('strokes:visible', visible);
    });
    socket.on('stroke', (stroke: Stroke) => {
      if (!board) return;
      let b = boards.get(board); if (!b) { b = { strokes: [] }; boards.set(board, b); }
      b.strokes.push(stroke);
      // Notify peers whose viewport intersects
      ns.to(`board:${board}`).emit('stroke', stroke);
    });
  });
}

function intersects(a: [number, number, number, number], b: [number, number, number, number]): boolean {
  return !(a[0] > b[0] + b[2] || a[0] + a[2] < b[0] || a[1] > b[1] + b[3] || a[1] + a[3] < b[1]);
}

import { Request, Response, NextFunction } from 'express';
import { OrderModel } from '../models/order.model';
import { sendEmail } from '../services/email.service';

export const place = async (req: Request, res: Response, next: NextFunction) => {
  try {
    if (req.body.total < 0) return res.status(400).json({ error: 'INVALID' });
    const order = await OrderModel.create({ userId: req.user!.id, total: req.body.total });
    await sendEmail({ to: req.user!.email, subject: 'Order placed', body: `Order ${order._id}` });
    res.json({ order });
  } catch (err) { next(err); }
};

export type PlaceOrderInput = { userId: string; total: number; email: string };
export type OrderRepoPort = { create(input: { userId: string; total: number }): Promise<{ id: string }> };
export type MailerPort = { send(input: { to: string; subject: string; body: string }): Promise<void> };

export class InvalidTotalError extends Error { constructor() { super('INVALID_TOTAL'); } }

export async function placeOrder(input: PlaceOrderInput, ports: { orders: OrderRepoPort; mailer: MailerPort }) {
  if (input.total < 0) throw new InvalidTotalError();
  const order = await ports.orders.create({ userId: input.userId, total: input.total });
  await ports.mailer.send({ to: input.email, subject: 'Order placed', body: `Order ${order.id}` });
  return order;
}

