type EventsMap = {
  'notification:click': { id: string };
  'modal:open': { name: string };
  'modal:close': void;
};

type Listener<K extends keyof EventsMap> = (data: EventsMap[K]) => void;

const listeners: { [K in keyof EventsMap]?: Set<Listener<K>> } = {};

export function emit<K extends keyof EventsMap>(event: K, data: EventsMap[K]) {
  const set = listeners[event] as Set<Listener<K>> | undefined;
  if (!set) return;
  for (const l of set) l(data);
}

export function subscribe<K extends keyof EventsMap>(event: K, listener: Listener<K>): () => void {
  let set = listeners[event] as Set<Listener<K>> | undefined;
  if (!set) { set = new Set(); (listeners as Record<string, Set<unknown>>)[event] = set as unknown as Set<unknown>; }
  set.add(listener);
  return () => { set!.delete(listener); };
}

import { useEffect } from 'react';
import { subscribe } from './event-bus';

export function useEvent<K extends Parameters<typeof subscribe>[0]>(event: K, listener: Parameters<typeof subscribe>[1]) {
  useEffect(() => subscribe(event, listener as never), [event, listener]);
}

